import{_ as o,o as t,c as d,a3 as n}from"./chunks/framework.BveOjhN0.js";const p=JSON.parse('{"title":"多租户与版本","description":"","frontmatter":{},"headers":[],"relativePath":"cosmos/basic-app/multi-tenancy.md","filePath":"cosmos/basic-app/multi-tenancy.md","lastUpdated":1783300196000}'),c={name:"cosmos/basic-app/multi-tenancy.md"};function a(i,e,r,l,s,u){return t(),d("div",null,[...e[0]||(e[0]=[n('<h1 id="多租户与版本" tabindex="-1">多租户与版本 <a class="header-anchor" href="#多租户与版本" aria-label="Permalink to &quot;多租户与版本&quot;">​</a></h1><p>XiHan.BasicApp 是一套 <strong>B2B SaaS 多租户内核</strong>：一份代码、一套部署，同时承载多个互不可见的租户（企业客户），并以**版本（Edition）**作为订阅售卖与功能门控的单元。本页讲清楚隔离怎么落地、登录后落到哪里、超级管理员如何跨租户运维、版本白名单如何在运行时门控权限，以及请求如何解析到租户上下文。</p><p>权限码、数据范围、字段脱敏等细节见 <a href="./permissions">权限模型</a>；框架层的租户上下文、解析链与存储见 <a href="./../framework/packages/multitenancy">XiHan.Framework.MultiTenancy</a>。本页聚焦 BasicApp 应用层的租户与版本机制。</p><h2 id="隔离模型-字段级隔离-tenantid-0-约定" tabindex="-1">隔离模型：字段级隔离 + <code>TenantId=0</code> 约定 <a class="header-anchor" href="#隔离模型-字段级隔离-tenantid-0-约定" aria-label="Permalink to &quot;隔离模型：字段级隔离 + `TenantId=0` 约定&quot;">​</a></h2><p>BasicApp 默认走<strong>字段级隔离（Field）</strong>：所有业务实体继承自 <code>BasicAppEntity</code>（底层是框架的 <code>SugarMultiTenantEntity&lt;long&gt;</code>），带一个 <code>TenantId</code> 列，查询按当前租户上下文自动过滤，无需业务代码手动拼条件。</p><p>隔离模式由 <code>SysTenant.IsolationMode</code>（<code>TenantIsolationMode</code>）声明，支持三种，<code>SysTenant</code> 还预留了独立库连接串等字段：</p><table tabindex="0"><thead><tr><th>模式</th><th>含义</th></tr></thead><tbody><tr><td><code>Field</code>（默认）</td><td>同库同表，靠 <code>TenantId</code> 列区分租户数据</td></tr><tr><td><code>Database</code></td><td>每租户独立数据库（<code>ConnectionString</code> 加密存储，需 <code>InitializeDatabase</code> 建库建表种子）</td></tr><tr><td><code>Schema</code></td><td>同库不同 Schema</td></tr></tbody></table><h3 id="框架层-long-null-与应用层-tenantid-0-的关系" tabindex="-1">框架层 <code>long?</code>/null 与应用层 <code>TenantId=0</code> 的关系 <a class="header-anchor" href="#框架层-long-null-与应用层-tenantid-0-的关系" aria-label="Permalink to &quot;框架层 `long?`/null 与应用层 `TenantId=0` 的关系&quot;">​</a></h3><p>这是理解本系统隔离的关键，两层用<strong>不同的空值语义</strong>表达&quot;全局/无租户&quot;：</p><ul><li><strong>框架层</strong>：<code>ICurrentTenant.Id</code> 是 <code>long?</code>。<code>null</code>（或 <code>0</code>）表示<strong>当前请求没有租户上下文</strong>，即平台运维态（宿主态）。框架的租户查询过滤器在无上下文时关闭。</li><li><strong>BasicApp 应用层落库约定</strong>（见 <code>BasicAppEntity</code> 注释）：平台级/全局记录统一落 <strong><code>TenantId=0</code></strong>（&quot;平台租户&quot;占位），<strong>不得用 NULL</strong>；业务租户 Id 从 1 开始分配，0 号租户由平台保留。</li></ul><p>二者衔接的规则：</p><ul><li>平台判定统一以 <code>currentTenant.IsPlatformOperation()</code> 为准，其实现就是 <code>Id is null or 0</code>（见 <code>CurrentTenantPlatformExtensions</code>）。</li><li>查询&quot;全局 + 私有&quot;合并时用 <code>WHERE TenantId IN (0, {currentTenantId})</code>。授权快照构建即按此规则：绑定行按 <code>TenantId == 当前租户 || TenantId == 0</code> 生效，平台态（无上下文）则仅 <code>TenantId=0</code> 的全局绑定生效，防止多租户成员在平台态聚合出跨租户权限。</li><li>如需 <code>IsGlobal</code> 语义，实体在 Expand 里以只读派生属性 <code>IsGlobal =&gt; TenantId == 0</code> 暴露，<strong>不落库</strong>（避免与 <code>TenantId</code> 漂移）。</li><li>只有平台运维态才允许维护 <code>TenantId=0</code> 的全局模板（菜单/权限/角色/版本等）；租户态（<code>Id&gt;0</code>）对全局模板一律拒绝写入，避免某租户改动波及所有租户。</li></ul><blockquote><p>服务层通过框架注入自动写入 <code>TenantId</code>，业务代码禁止直接操纵。需要临时切换上下文（如在新租户内开通、平台态全局定位账号）时用 <code>ICurrentTenant.Change(...)</code>，<code>using</code> 作用域结束自动恢复。</p></blockquote><h2 id="登录与落点-邮箱全局唯一-先登录后选租户" tabindex="-1">登录与落点：邮箱全局唯一，先登录后选租户 <a class="header-anchor" href="#登录与落点-邮箱全局唯一-先登录后选租户" aria-label="Permalink to &quot;登录与落点：邮箱全局唯一，先登录后选租户&quot;">​</a></h2><p>BasicApp 采用<strong>先登录后选租户</strong>：登录页不再让用户选租户，统一在平台态（<code>_currentTenant.Change(null)</code>）完成身份认证，成功后按用户的成员关系自动决定落点。</p><ul><li><strong>邮箱是全平台唯一的登录身份标识</strong>。注册、开通租户管理员、找回密码都强制校验邮箱且全局唯一（<code>ExistsEmailGloballyAsync</code>）。平台账号也可用用户名登录。</li><li>支持密码登录、邮箱验证码登录、第三方（OAuth）登录，均在平台态定位用户后走统一落点逻辑（<code>IssueLoginTokenWithLandingAsync</code>）。</li></ul><h3 id="落点策略" tabindex="-1">落点策略 <a class="header-anchor" href="#落点策略" aria-label="Permalink to &quot;落点策略&quot;">​</a></h3><p>落点由 <code>ResolveLoginLandingAsync</code> 决定，返回 <code>null</code> 表示落<strong>平台态（前端控制中心）</strong>：</p><table tabindex="0"><thead><tr><th>情形</th><th>落点</th></tr></thead><tbody><tr><td>平台账号（<code>TenantId=0</code>，如超管）</td><td>平台态控制中心</td></tr><tr><td>拥有超管角色（全局绑定）</td><td>平台态控制中心</td></tr><tr><td>恰好一个可用租户成员</td><td>直接进入该租户（免选择）</td></tr><tr><td>零个或多个可用租户</td><td>平台态控制中心（前端展示租户选择/原因）</td></tr></tbody></table><p>&quot;唯一租户&quot;也要确认可用（正常 / 已配置 / 未过期）才直接进入，不可用则落控制中心由前端展示原因。签发的令牌只在进入具体租户时带 <code>TenantId</code> claim，平台态不带。</p><h3 id="随时切换租户" tabindex="-1">随时切换租户 <a class="header-anchor" href="#随时切换租户" aria-label="Permalink to &quot;随时切换租户&quot;">​</a></h3><p>登录后可通过 <code>SwitchTenantAsync</code>（<code>api/Auth</code>）在有权限的租户之间切换（类似 GitHub 切换 Org）：</p><ul><li>目标 <code>TenantId</code> 归一：<code>null</code> 或 <code>&lt;=0</code> 视为平台运维态。</li><li>切到具体租户：必须是该租户的<strong>有效成员</strong>（普通用户），或是<strong>超管</strong>（可进任意租户，见下）。</li><li>进入平台运维态：仅超管，或拥有 <code>PlatformAdmin</code> 成员身份者。</li><li>切换会在目标上下文内<strong>重建授权快照并签发新令牌</strong>——权限随落点租户实时重算，不沿用旧令牌里的声明。</li></ul><p>可切换的租户列表来自当前用户的有效成员关系（<code>GetActiveByUserIdAsync</code>，跨租户读取、忽略租户过滤），前端用 <code>TenantSwitcherDto</code> 渲染切换器。</p><h2 id="成员关系-systenantuser" tabindex="-1">成员关系：<code>SysTenantUser</code> <a class="header-anchor" href="#成员关系-systenantuser" aria-label="Permalink to &quot;成员关系：`SysTenantUser`&quot;">​</a></h2><p>&quot;谁能进入哪个租户&quot;由 <code>SysTenantUser</code>（<code>Sys_Tenant_User</code>）承载——它是 用户 × 租户 的多对多成员表，是跨租户协作与平台运维统一建模的入口。语义上区分：</p><ul><li><code>SysUser.TenantId</code> = 用户主账号的归属租户（注册地）</li><li><code>SysTenantUser.TenantId</code> = 用户拥有成员身份的租户（含主租户 + 外部协作租户）</li></ul><p>所有租户访问（含主属）都统一走本表，鉴权路径一致。关键字段：</p><ul><li><code>MemberType</code>（<code>TenantMemberType</code>）：<code>Owner</code> / <code>Admin</code> / <code>Member</code> / <code>External</code> / <code>Guest</code> / <code>Consultant</code> / <code>PlatformAdmin</code>。 <ul><li>注意：<code>MemberType</code> 表达&quot;成员身份类型&quot;而非&quot;权限级别&quot;，<strong>服务层禁止用它直接鉴权</strong>（如 <code>if MemberType==Admin</code>），必须走 RBAC 权限链；它只用于成员列表分类、邀请流程控制、<code>PlatformAdmin</code> 创建校验。</li></ul></li><li><code>InviteStatus</code>（<code>TenantMemberInviteStatus</code>）：<code>Pending → Accepted / Rejected / Revoked / Expired</code>。仅 <code>Accepted</code> 且 <code>Status=Valid</code> 且当前时间在生效/失效区间内的成员关系才可用于鉴权。</li><li><code>EffectiveTime</code> / <code>ExpirationTime</code>：外部协作者/访客常用的时效控制。</li></ul><h2 id="超级管理员-平台态运维-代管租户" tabindex="-1">超级管理员：平台态运维 + 代管租户 <a class="header-anchor" href="#超级管理员-平台态运维-代管租户" aria-label="Permalink to &quot;超级管理员：平台态运维 + 代管租户&quot;">​</a></h2><p>超级管理员（角色编码 <code>super_admin</code>，运行时特判通配 <code>*</code>）是平台运营方账号：</p><ul><li><strong>恒落平台态</strong>：无论有无租户成员关系，登录都落平台控制中心。</li><li><strong>权限通配</strong>：授权快照里带 <code>*</code>，放行一切，且<strong>不受版本门控</strong>（见下）。</li><li><strong>可切入任意租户代为管理（impersonation）</strong>：<code>SwitchTenantAsync</code> 里超管无需是目标租户成员即可进入。进入后在<strong>目标租户上下文内重建授权快照</strong>——即代管期间以目标租户的口径操作，行为可被审计追溯。</li></ul><p>除超管外，拥有 <code>PlatformAdmin</code> 成员身份的账号也可进入平台运维态（用于运维/客服/风控）。</p><h2 id="租户版本-edition-权限白名单-运行时门控" tabindex="-1">租户版本（Edition）：权限白名单 + 运行时门控 <a class="header-anchor" href="#租户版本-edition-权限白名单-运行时门控" aria-label="Permalink to &quot;租户版本（Edition）：权限白名单 + 运行时门控&quot;">​</a></h2><p>版本是 B2B SaaS 的<strong>订阅售卖单元 + 功能门控单元</strong>。三张表分工明确：</p><table tabindex="0"><thead><tr><th>实体</th><th>表</th><th>职责</th></tr></thead><tbody><tr><td><code>SysTenantEdition</code></td><td><code>Sys_Tenant_Edition</code></td><td>版本能做什么、卖多少（<code>EditionCode</code>/<code>Price</code>/<code>BillingPeriodMonths</code>/<code>UserLimit</code>/<code>StorageLimit</code>/<code>IsDefault</code>）</td></tr><tr><td><code>SysTenantEditionPermission</code></td><td><code>Sys_Tenant_Edition_Permission</code></td><td>版本 → 权限<strong>白名单</strong>映射（<code>EditionId</code> × <code>PermissionId</code>，唯一）</td></tr><tr><td><code>SysTenant.EditionId</code></td><td><code>Sys_Tenant</code></td><td>某租户订阅了哪个版本（<code>null</code> 时取 <code>IsDefault=true</code> 的默认版本）</td></tr></tbody></table><p>内置版本种子（<code>SaasTenantEditionSeeder</code>）：<code>free</code>（免费/默认，只读+基础成员）、<code>basic</code>（+组织/用户/角色管理）、<code>pro</code>（+高级权限/审计/安全）、<code>enterprise</code>（授予全部<strong>租户安全</strong>权限、不限配额）。版本记录本身是平台级（<code>TenantId=0</code>），由平台运营维护。</p><p>关键约束（见 <code>SysTenantEdition</code> 与领域服务）：</p><ul><li><code>EditionCode</code> 全局唯一，如 <code>free</code>/<code>basic</code>/<code>pro</code>/<code>enterprise</code>。</li><li>同一时刻仅一个 <code>IsDefault=true</code>；设默认时先清其它默认（<code>ClearDefaultEditionsAsync</code>），且默认版本必须处于启用状态、不能被直接取消或禁用。</li><li>版本白名单只能绑定<strong>平台级全局权限</strong>（<code>permission.IsGlobal</code>，即 <code>TenantId=0</code>）且权限须启用——非全局权限不应被版本门控。</li></ul><h3 id="运行时门控-越白名单的权限被拒" tabindex="-1">运行时门控：越白名单的权限被拒 <a class="header-anchor" href="#运行时门控-越白名单的权限被拒" aria-label="Permalink to &quot;运行时门控：越白名单的权限被拒&quot;">​</a></h3><p>门控在 <code>AuthorizationSnapshotQueryService</code> 构建授权快照时叠加（<code>ApplyEditionGatingAsync</code>）——用户在某租户能生效的权限，被该租户所属版本的白名单<strong>收窄取交集</strong>：越出白名单的权限即便被授予，也不进入生效权限集，等同被拒。</p><p>门控的<strong>例外（不门控）</strong>，任一命中即放行原快照：</p><ul><li>超管通配 <code>*</code>；</li><li>平台运维态（无租户上下文）；</li><li>租户未绑定版本（<code>EditionId</code> 为空）；</li><li>版本未配置白名单（白名单为空）——避免把租户误锁死（fail-open 仅限&quot;未启用门控&quot;这一语义）。</li></ul><p>性能上，门控白名单走<strong>独立的版本门控缓存</strong>（<code>SaasEditionGateCacheItem</code>，<code>CacheName</code> = <code>EditionGate</code>，10 分钟 TTL），在 per-user 授权快照缓存<strong>之外</strong>按当前租户上下文叠加，避免切换租户后缓存串味，鉴权热路径不必每请求查库。版本白名单/租户换版的写路径会调 <code>InvalidateEditionGateAsync</code> 失效缓存（事务提交后生效）。</p><h3 id="开通一站式-建管理员-角色-授权" tabindex="-1">开通一站式：建管理员 + 角色 + 授权 <a class="header-anchor" href="#开通一站式-建管理员-角色-授权" aria-label="Permalink to &quot;开通一站式：建管理员 + 角色 + 授权&quot;">​</a></h3><p>创建租户时若同时提供管理员账号信息（<code>AdminUserName</code> + <code>AdminPassword</code> + <code>AdminEmail</code>），<code>CreateTenantAsync</code> 会调 <code>ProvisionTenantAdminAsync</code> 一站式开通（<code>TenantProvisionDomainService</code>），全程在新租户上下文内进行：</p><ol><li><strong>确保版本</strong>：租户未指定则取默认版本并回写 <code>SysTenant.EditionId</code>；</li><li><strong>建管理员</strong>：创建 <code>SysUser</code>（校验邮箱全局唯一）+ <code>SysUserSecurity</code>（密码哈希）+ <code>SysTenantUser</code>（<code>MemberType=Owner</code>、<code>InviteStatus=Accepted</code>）；</li><li><strong>建 Owner 角色并按白名单授权</strong>：创建角色 <code>tenant_owner</code>（数据范围 <code>All</code>），把该版本白名单里的有效权限批量写成 <code>SysRolePermission</code>（<code>Grant</code>）；</li><li><strong>绑定</strong>：把管理员挂到 Owner 角色（<code>SysUserRole</code>）。</li></ol><p>于是新租户开通即&quot;能登录、有 Owner、拥有版本范围内的全部权限&quot;，无需人工逐项授权。</p><h3 id="降级自动回收越权授权" tabindex="-1">降级自动回收越权授权 <a class="header-anchor" href="#降级自动回收越权授权" aria-label="Permalink to &quot;降级自动回收越权授权&quot;">​</a></h3><p>当版本白名单<strong>收窄</strong>（撤销/停用某条版本权限映射），系统会<strong>自动回收该版本下各租户存量的越权授权</strong>（<code>ReconcileEditionTenantsAuthorizationAsync</code> → <code>ReconcileTenantAuthorizationWithEditionAsync</code>）：</p><ul><li>触发点：<code>RevokeTenantEditionPermissionAsync</code>（撤销）、<code>UpdateTenantEditionPermissionStatusAsync</code>（映射被置为非 <code>Valid</code>）。恢复为有效则无需回收。</li><li>回收动作：把该租户下<strong>超出白名单</strong>的 <code>SysRolePermission</code> / <code>SysUserPermission</code> 存量行置为 <code>Invalid</code> 并记 <code>ExpirationTime</code> 与回收原因（&quot;套餐变更回收：超出当前版本权限白名单&quot;）。</li><li>边界：只回收该租户<strong>自有</strong>绑定行（<code>TenantId=本租户</code>）；全局行（<code>TenantId=0</code>）属平台运维资产，不在回收范围。白名单为空视为&quot;门控未启用&quot;，不回收以防误清。</li></ul><blockquote><p>运行时门控（快照收窄）+ 降级回收（存量清理）是两道并行防线：前者保证越权权限当下不生效，后者把已落库的越权授权行物理失效，避免日后升级/门控放开后旧越权授权&quot;复活&quot;。</p></blockquote><h2 id="租户解析-请求如何落到租户上下文" tabindex="-1">租户解析：请求如何落到租户上下文 <a class="header-anchor" href="#租户解析-请求如何落到租户上下文" aria-label="Permalink to &quot;租户解析：请求如何落到租户上下文&quot;">​</a></h2><p>一次请求进入后，框架在 HTTP 管线里执行<strong>租户解析链</strong>（<code>XiHanTenantResolveMiddleware</code>，在 <code>XiHan.Framework.Web.Api</code>），把解析结果写入 <code>ICurrentTenant</code>。解析贡献者按顺序命中即止（<code>Handled=true</code> 短路）：</p><table tabindex="0"><thead><tr><th>顺序</th><th>贡献者</th><th>来源</th><th>说明</th></tr></thead><tbody><tr><td>1</td><td><code>CurrentUserTenantResolveContributor</code></td><td>已登录用户的 <code>TenantId</code>（来自 JWT claim）</td><td>首位插入，是主路径；已认证且带租户则据此解析</td></tr><tr><td>2</td><td><code>HeaderTenantResolveContributor</code></td><td>请求头 <code>X-Tenant-Id</code>（默认键含 <code>X-Tenant-Id</code>/<code>x-tenant-id</code>/<code>TenantId</code>）</td><td><code>EnableHeaderResolve</code> 默认开</td></tr><tr><td>3</td><td><code>QueryStringTenantResolveContributor</code></td><td>查询串 <code>tenantId</code> / <code>tenant</code></td><td><code>EnableQueryStringResolve</code> 默认开</td></tr></tbody></table><p>配置节 <code>XiHan:MultiTenancy:Resolve</code>（<code>XiHanTenantResolveOptions</code>）可调头/查询串键名、开关与 <code>FallbackTenant</code>。</p><p>对 BasicApp 而言，<strong>主路径是令牌里的 <code>TenantId</code></strong>：先登录后选租户，登录时按落点决定令牌是否带 <code>TenantId</code> claim（平台态不带），之后每次请求由 <code>CurrentUserTenantResolveContributor</code> 据此还原上下文；换租户则重新签发令牌。解析链的完整机制见 <a href="./../framework/packages/multitenancy">XiHan.Framework.MultiTenancy</a>。</p><h2 id="与权限的交叉点" tabindex="-1">与权限的交叉点 <a class="header-anchor" href="#与权限的交叉点" aria-label="Permalink to &quot;与权限的交叉点&quot;">​</a></h2><p>版本门控是租户维度对权限的<strong>再收窄</strong>，叠在 RBAC/ABAC 判定链之上。完整判定链（认证 → 租户解析 → RBAC → ABAC → 数据范围 → 字段脱敏）与权限码/数据范围/FLS 细节见 <a href="./permissions">权限模型</a>。要点回顾：</p><ul><li>授权快照按 <code>(当前租户 OR 全局 TenantId=0)</code> 聚合绑定行，再被当前租户版本白名单取交集收窄。</li><li>超管（<code>*</code>）与平台运维态不受版本门控。</li><li>版本白名单只挂平台级全局权限。</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="./permissions">权限模型</a>：RBAC + ABAC、权限码、数据范围、字段脱敏</li><li><a href="./architecture">系统架构</a>：租户解析在请求管道中的位置</li><li><a href="./../framework/packages/multitenancy">XiHan.Framework.MultiTenancy</a>：框架层租户上下文、解析链与存储</li></ul>',62)])])}const g=o(c,[["render",a]]);export{p as __pageData,g as default};
